var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"……좋습니다. 정리해 보죠.","JPN":"……いいでしょう。では、整理してみましょう。","ENG":"All right. Shall we?","TWN":"……好，來整理整理吧。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"성무 SI3E은 <color=#ffd34c>관리 거부 구역</color>에서 온 제보로 시작되었습니다.\xA0","JPN":"聖務SI3Eは<color=#ffd34c>管理拒否区域</color>からの情報提供で始まりました。\xA0","ENG":"A tip from the <color=#ffd34c>Anti-Administration Zone</color> initiated Sacred Mission SI3E.\xA0","TWN":"聖務SI3E是因從<color=#ffd34c>拒絕管理區域</color>來的獲報而開始的。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"심의회 멤버이니 관리 거부 구역에 대해서는 한 번쯤 들어 봤겠죠, 시스터 루퍼?","JPN":"審議会のメンバーですから、管理拒否区域については聞いたことがあるでしょう。シスタールーパー。","ENG":"You have probably heard of the Anti-Administration Zone as an Investigation Council member. Is that correct, Sister Looper?","TWN":"身為議會成員，你應該聽說過拒絕管理區域吧，洛珀姊妹？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"몰라, 그런 거.","JPN":"そんなの知らないね。","ENG":"Dunno.","TWN":"我不知道，"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"머리 쓰는 건 꺽다리 역할이거든. 내 일은 침식체들 천국 직행 버스 태워 보내기고.","JPN":"頭使うのはのっぽの仕事だから。アタシの仕事は侵食体を天国直行バスに乗せること。","ENG":"Long Legs was in charge of all the thinking. My job was to send those C.O.s to the doorstep of Heaven.","TWN":"動腦的事是高個子在負責的，我只負責將侵蝕體送上地獄直達列車。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"그러니까 궁금한 게 있으면 꺽다리한테 묻든가.\xA0","JPN":"だから気になることあったらのっぽに聞いてよ。\xA0","ENG":"So if you have any questions, go ask him.\xA0","TWN":"所以你有什麼問題就去問高個子吧。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"퍽이나 귀여운 후배님이로군요.","JPN":"本当に可愛い後輩ですね。","ENG":"You are not as cute as the Cardinal said.","TWN":"還真是可愛的新人呢。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"왜? 불만 있어?","JPN":"何？　文句ある？","ENG":"What? You gotta problem with that?","TWN":"怎樣？有意見嗎？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"네. 당신이 썩 마음에 들지는 않습니다.","JPN":"はい。あなたをあまり好きになれなさそうです。","ENG":"Yes, I do. I do not really like you.","TWN":"有，我對你很有意見。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"하지만 당신은 사건의 주요 참고인입니다. 심문을 빨리 끝내고 싶으면 협조적인 태도로 임하세요.","JPN":"ですがあなたは事件の重要参考人です。早く審問を終わらせたいのなら、協力的な態度を見せてください。","ENG":"However, you are the primary witness in the case. If you want the interrogation to end swiftly, be cooperative.","TWN":"不過你是這次事件的主要證人，若想盡快結束審問，那就麻煩態度配合一點。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"쳇…….","JPN":"ちっ……","ENG":"Sheesh...","TWN":"嘖……"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"관리 거부 구역이란 종교나 문화, 혹은 정치적 이유로 관리국이 중심인 대 침식전 체제를 거부한 구역을 지칭합니다.","JPN":"管理拒否区域とは宗教や文化、あるいは政治的な理由で、管理局が中心である対侵食戦体制を拒否した区域のことをいいます。","ENG":"The Anti-Administration Zone refers to areas that, for political, cultural, and religious reasons, have rejected the Anti-Corruption system that is centered on the Administration.","TWN":"拒絕管理區域，指的就是管理局因宗教、文化，或是政治因素，而拒絕反侵蝕體作戰的區域。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"작게는 원리주의 종교 공동체부터 크게는 국가까지 포함하는 개념이죠.","JPN":"原理主義の宗教共同体から、国家までを含む概念です。","ENG":"It is a broad concept that includes everything from fundamentalist religious communities to entire nations.","TWN":"這件事牽涉範圍小至整個宗教共同體，大至整個國家。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"이런 곳은 북방 합의체 같은 예외를 제외하면, 대부분 침식현상에 대응할 여력이 부족합니다.","JPN":"こういうところは北方合意体のような例外を除くと､ほとんどが侵食現象に対応しきれません｡","ENG":"However, most of these places lack the capacity to respond to the Counterside Effect, excluding Northern Union.","TWN":"這種地方，除非像是北方和議會這種例外，大部分是沒有餘力應付侵蝕現象的。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그러나 성황청은 관리 거부 구역에서도 자원 봉사라는 형태로 침식 현상에 고통받는 이들을 돕고 있죠.","JPN":"ですが聖皇庁は管理拒否区域でもボランティアという形で侵食現象で苦しんでいる人たちを助けています｡","ENG":"However, the Holy Curia volunteers to help those suffering from the Counterside Effect in these Anti-Administration Zones.","TWN":"但聖皇廳在拒絕管理區域，也有以義工的形式幫助受侵蝕現象所苦的人對吧？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"아, 맞다. 그 말 들으니 기억나네.","JPN":"あ、そうだ。それ聞いたら思い出したよ。","ENG":"Oh, right. I remember now that you mention it.","TWN":"喔，對，聽你這麼說我想起來了。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"자원 봉사라고 뻥치고 이단들 사고 치나 감시하는 그거?\xA0","JPN":"ボランティアって嘘ついて、異端者を監視するあれだろ？\xA0","ENG":"The fake \\"volunteering\\" you do to monitor if those heretics aren't causing any trouble, right?\xA0","TWN":"義工只是幌子，實際上是監視異端有沒有惹事，你是指這個吧？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"}}}}]`);export{e as default};